      "type": "object",
      "required": ["type", "name"],
      "properties": {
        "name": { "type": "string" },
        "type": { "enum": ["file", "directory"] },
        "contents": {
          "type": "array",
          "items": { "$ref": "#/$defs/node" }
        }
      },
      "allOf": [
        {
          "if": { "properties": { "type": { "const": "file" } } },
          "then": {
            "not": { "required": ["contents"] },
            "description": "Files must not have a contents property."
          }
        }
      ]
    },
    "report": {
      "type": "object",
      "required": ["type", "directories", "files"],
      "properties": {
        "type": { "const": "report" },
        "directories": { "type": "integer", "minimum": 0 },
        "files": { "type": "integer", "minimum": 0 }
      }
    }
  }
}

